//! Typed AST node wrappers generated by the [`ast_node!`] macro, plus their
//! convenience accessors and the [`Expr`] expression sum. These are thin views
//! over the CST — no allocation, no semantic analysis.
//!
//! Accessors return typed wrappers (a child [`AstNode`], an [`Expr`], or a typed
//! [token](super::tokens)) rather than raw [`SyntaxNode`]s wherever the child
//! has a wrapper, and fall back to `Option`/iterator shapes that degrade
//! gracefully on malformed input. The underlying [`SyntaxNode`] is always
//! reachable through [`AstNode::syntax`].

use rowan::ast::{AstChildren, AstNode, support};

use super::tokens::{AstToken, Ident, Operator, child_token};
use crate::syntax::{JuliaLanguage, SyntaxKind, SyntaxNode, SyntaxToken};

macro_rules! ast_node {
    ($(#[$meta:meta])* $name:ident, $kind:expr) => {
        $(#[$meta])*
        #[derive(Debug, Clone, PartialEq, Eq, Hash)]
        pub struct $name(SyntaxNode);

        impl AstNode for $name {
            type Language = JuliaLanguage;

            fn can_cast(kind: SyntaxKind) -> bool {
                kind == $kind
            }

            fn cast(syntax: SyntaxNode) -> Option<Self> {
                Self::can_cast(syntax.kind()).then_some(Self(syntax))
            }

            fn syntax(&self) -> &SyntaxNode {
                &self.0
            }
        }
    };
}

ast_node!(Root, SyntaxKind::ROOT);
ast_node!(Literal, SyntaxKind::LITERAL);
ast_node!(StringLiteral, SyntaxKind::STRING_LITERAL);
