/// The expression sum: any node that can appear in value position, cast to a
/// dedicated variant when one exists and to [`Expr::Other`] otherwise.
///
/// `Other` keeps the sum *total* over expression kinds — the Julia grammar is a
/// growing skeleton, so a kind that has no wrapper yet (e.g. `RANGE_EXPR`,
/// `COMPARISON_EXPR`) still round-trips through `Expr` instead of being silently
/// dropped from an operand accessor. Match `Other`'s [`SyntaxNode`] (or its
/// [`kind`](SyntaxNode::kind)) for those.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub enum Expr {
    Literal(Literal),
    StringLiteral(StringLiteral),
    CmdLiteral(CmdLiteral),
    NonstandardIdentifier(NonstandardIdentifier),
    Interpolation(Interpolation),
    Name(Name),
    BinaryExpr(BinaryExpr),
    UnaryExpr(UnaryExpr),
    ParenExpr(ParenExpr),
    TupleExpr(TupleExpr),
    VectExpr(VectExpr),
    MatrixExpr(MatrixExpr),
    Comprehension(Comprehension),
    Generator(Generator),
    CallExpr(CallExpr),
    IndexExpr(IndexExpr),
    DotCallExpr(DotCallExpr),
    CurlyExpr(CurlyExpr),
    Braces(Braces),
    AssignmentExpr(AssignmentExpr),
    ArrowExpr(ArrowExpr),
    TernaryExpr(TernaryExpr),
    IfExpr(IfExpr),
    BeginExpr(BeginExpr),
    QuoteExpr(QuoteExpr),
    WhileExpr(WhileExpr),
    ForExpr(ForExpr),
    LetExpr(LetExpr),
    TryExpr(TryExpr),
    DoExpr(DoExpr),
    FunctionDef(FunctionDef),
    MacroCall(MacroCall),
    SplatExpr(SplatExpr),
    WhereExpr(WhereExpr),
    TypeAnnotation(TypeAnnotation),
    ReturnExpr(ReturnExpr),
    BreakExpr(BreakExpr),
    ContinueExpr(ContinueExpr),
    /// An expression-position node without a dedicated variant (see the type
    /// docs). Guaranteed to satisfy [`is_expr_kind`].
    Other(SyntaxNode),
}

/// Whether `kind` is a node that can occur in expression (value) position. The
/// complement is the structural scaffolding — clauses, argument lists,
/// signatures, statements, blocks — plus every token kind.
pub fn is_expr_kind(kind: SyntaxKind) -> bool {
    use SyntaxKind::*;
    matches!(
        kind,
        LITERAL
            | STRING_LITERAL
            | CMD_LITERAL
            | NONSTANDARD_IDENTIFIER
            | INTERPOLATION
            | NAME
            | BINARY_EXPR
            | RANGE_EXPR
            | COMPARISON_EXPR
            | UNARY_EXPR
            | PAREN_EXPR
            | TUPLE_EXPR
            | BARE_TUPLE_EXPR
            | PAREN_BLOCK
            | VECT_EXPR
            | MATRIX_EXPR
            | TYPED_MATRIX_EXPR
            | BRACESCAT_EXPR
            | COMPREHENSION
            | BRACES_COMPREHENSION
            | TYPED_COMPREHENSION
            | GENERATOR
            | CALL_EXPR
            | INDEX_EXPR
            | DOT_CALL_EXPR
            | CURLY_EXPR
            | BRACES
            | TYPE_ANNOTATION
            | WHERE_EXPR
            | SPLAT_EXPR
            | POSTFIX_EXPR
            | OPERATOR_ATOM
            | ASSIGNMENT_EXPR
            | ARROW_EXPR
            | JUXTAPOSE_EXPR
            | TERNARY_EXPR
            | IF_EXPR
            | FUNCTION_DEF
            | BEGIN_EXPR
            | WHILE_EXPR
            | FOR_EXPR
            | LET_EXPR
            | QUOTE_EXPR
            | QUOTE_SYM
            | TRY_EXPR
            | STRUCT_DEF
            | ABSTRACT_DEF
            | PRIMITIVE_DEF
            | MODULE_DEF
            | DO_EXPR
            | RETURN_EXPR
            | BREAK_EXPR
            | CONTINUE_EXPR
            | MACRO_CALL
    )
}

impl AstNode for Expr {
    type Language = JuliaLanguage;

    fn can_cast(kind: SyntaxKind) -> bool {
        is_expr_kind(kind)
    }

    fn cast(syntax: SyntaxNode) -> Option<Self> {
        let expr = match syntax.kind() {
            SyntaxKind::LITERAL => Expr::Literal(Literal(syntax)),
            SyntaxKind::STRING_LITERAL => Expr::StringLiteral(StringLiteral(syntax)),
            SyntaxKind::CMD_LITERAL => Expr::CmdLiteral(CmdLiteral(syntax)),
            SyntaxKind::NONSTANDARD_IDENTIFIER => {
                Expr::NonstandardIdentifier(NonstandardIdentifier(syntax))
            }
            SyntaxKind::INTERPOLATION => Expr::Interpolation(Interpolation(syntax)),
            SyntaxKind::NAME => Expr::Name(Name(syntax)),
            SyntaxKind::BINARY_EXPR => Expr::BinaryExpr(BinaryExpr(syntax)),
            SyntaxKind::UNARY_EXPR => Expr::UnaryExpr(UnaryExpr(syntax)),
            SyntaxKind::PAREN_EXPR => Expr::ParenExpr(ParenExpr(syntax)),
            SyntaxKind::TUPLE_EXPR => Expr::TupleExpr(TupleExpr(syntax)),
            SyntaxKind::VECT_EXPR => Expr::VectExpr(VectExpr(syntax)),
            SyntaxKind::MATRIX_EXPR => Expr::MatrixExpr(MatrixExpr(syntax)),
            SyntaxKind::COMPREHENSION => Expr::Comprehension(Comprehension(syntax)),
            SyntaxKind::GENERATOR => Expr::Generator(Generator(syntax)),
            SyntaxKind::CALL_EXPR => Expr::CallExpr(CallExpr(syntax)),
            SyntaxKind::INDEX_EXPR => Expr::IndexExpr(IndexExpr(syntax)),
            SyntaxKind::DOT_CALL_EXPR => Expr::DotCallExpr(DotCallExpr(syntax)),
            SyntaxKind::CURLY_EXPR => Expr::CurlyExpr(CurlyExpr(syntax)),
            SyntaxKind::BRACES => Expr::Braces(Braces(syntax)),
            SyntaxKind::ASSIGNMENT_EXPR => Expr::AssignmentExpr(AssignmentExpr(syntax)),
            SyntaxKind::ARROW_EXPR => Expr::ArrowExpr(ArrowExpr(syntax)),
            SyntaxKind::TERNARY_EXPR => Expr::TernaryExpr(TernaryExpr(syntax)),
            SyntaxKind::IF_EXPR => Expr::IfExpr(IfExpr(syntax)),
            SyntaxKind::BEGIN_EXPR => Expr::BeginExpr(BeginExpr(syntax)),
            SyntaxKind::QUOTE_EXPR => Expr::QuoteExpr(QuoteExpr(syntax)),
            SyntaxKind::WHILE_EXPR => Expr::WhileExpr(WhileExpr(syntax)),
            SyntaxKind::FOR_EXPR => Expr::ForExpr(ForExpr(syntax)),
            SyntaxKind::LET_EXPR => Expr::LetExpr(LetExpr(syntax)),
            SyntaxKind::TRY_EXPR => Expr::TryExpr(TryExpr(syntax)),
            SyntaxKind::DO_EXPR => Expr::DoExpr(DoExpr(syntax)),
            SyntaxKind::FUNCTION_DEF => Expr::FunctionDef(FunctionDef(syntax)),
            SyntaxKind::MACRO_CALL => Expr::MacroCall(MacroCall(syntax)),
            SyntaxKind::SPLAT_EXPR => Expr::SplatExpr(SplatExpr(syntax)),
            SyntaxKind::WHERE_EXPR => Expr::WhereExpr(WhereExpr(syntax)),
            SyntaxKind::TYPE_ANNOTATION => Expr::TypeAnnotation(TypeAnnotation(syntax)),
            SyntaxKind::RETURN_EXPR => Expr::ReturnExpr(ReturnExpr(syntax)),
            SyntaxKind::BREAK_EXPR => Expr::BreakExpr(BreakExpr(syntax)),
            SyntaxKind::CONTINUE_EXPR => Expr::ContinueExpr(ContinueExpr(syntax)),
            kind if is_expr_kind(kind) => Expr::Other(syntax),
            _ => return None,
        };
        Some(expr)
    }

    fn syntax(&self) -> &SyntaxNode {
        match self {
            Expr::Literal(it) => it.syntax(),
            Expr::StringLiteral(it) => it.syntax(),
            Expr::CmdLiteral(it) => it.syntax(),
            Expr::NonstandardIdentifier(it) => it.syntax(),
            Expr::Interpolation(it) => it.syntax(),
            Expr::Name(it) => it.syntax(),
            Expr::BinaryExpr(it) => it.syntax(),
            Expr::UnaryExpr(it) => it.syntax(),
            Expr::ParenExpr(it) => it.syntax(),
            Expr::TupleExpr(it) => it.syntax(),
            Expr::VectExpr(it) => it.syntax(),
            Expr::MatrixExpr(it) => it.syntax(),
            Expr::Comprehension(it) => it.syntax(),
            Expr::Generator(it) => it.syntax(),
            Expr::CallExpr(it) => it.syntax(),
            Expr::IndexExpr(it) => it.syntax(),
            Expr::DotCallExpr(it) => it.syntax(),
            Expr::CurlyExpr(it) => it.syntax(),
            Expr::Braces(it) => it.syntax(),
            Expr::AssignmentExpr(it) => it.syntax(),
            Expr::ArrowExpr(it) => it.syntax(),
            Expr::TernaryExpr(it) => it.syntax(),
            Expr::IfExpr(it) => it.syntax(),
            Expr::BeginExpr(it) => it.syntax(),
            Expr::QuoteExpr(it) => it.syntax(),
            Expr::WhileExpr(it) => it.syntax(),
            Expr::ForExpr(it) => it.syntax(),
            Expr::LetExpr(it) => it.syntax(),
            Expr::TryExpr(it) => it.syntax(),
            Expr::DoExpr(it) => it.syntax(),
            Expr::FunctionDef(it) => it.syntax(),
            Expr::MacroCall(it) => it.syntax(),
            Expr::SplatExpr(it) => it.syntax(),
            Expr::WhereExpr(it) => it.syntax(),
            Expr::TypeAnnotation(it) => it.syntax(),
            Expr::ReturnExpr(it) => it.syntax(),
            Expr::BreakExpr(it) => it.syntax(),
            Expr::ContinueExpr(it) => it.syntax(),
            Expr::Other(it) => it,
        }
    }
}

impl Name {
    /// The identifier token.
    pub fn ident(&self) -> Option<Ident> {
        child_token(&self.0)
    }
}

impl Literal {
    /// The `true`/`false` keyword token, when the literal is a boolean.
    pub fn bool_token(&self) -> Option<SyntaxToken> {
        support::token(&self.0, SyntaxKind::TRUE_KW)
            .or_else(|| support::token(&self.0, SyntaxKind::FALSE_KW))
    }
}

impl NonstandardIdentifier {
    /// The quoted body of a `var"..."` identifier (its `STRING_CONTENT` token).
    pub fn content(&self) -> Option<SyntaxToken> {
        support::token(&self.0, SyntaxKind::STRING_CONTENT)
    }
}

impl StringLiteral {
    /// The non-standard literal prefix token, e.g. `r` in `r"..."`.
    pub fn prefix(&self) -> Option<SyntaxToken> {
        support::token(&self.0, SyntaxKind::STRING_PREFIX)
    }

    /// The suffix flag token, e.g. `ims` in `r"pat"ims`.
    pub fn suffix(&self) -> Option<SyntaxToken> {
        support::token(&self.0, SyntaxKind::STRING_SUFFIX)
    }

    /// The interpolations embedded in the string, in source order.
    pub fn interpolations(&self) -> AstChildren<Interpolation> {
        support::children(&self.0)
    }

    /// The `STRING_CONTENT` chunks of the literal, in source order. A plain
    /// (non-interpolated) string joins to its full text.
    pub fn content_tokens(&self) -> impl Iterator<Item = SyntaxToken> {
        self.0
            .children_with_tokens()
            .filter_map(|el| el.into_token())
            .filter(|t| t.kind() == SyntaxKind::STRING_CONTENT)
    }
}

impl CmdLiteral {
    /// The non-standard literal prefix token, e.g. `` v `` in `` v`...` ``.
    pub fn prefix(&self) -> Option<SyntaxToken> {
        support::token(&self.0, SyntaxKind::STRING_PREFIX)
    }

    /// The suffix flag token following the closing backtick.
    pub fn suffix(&self) -> Option<SyntaxToken> {
        support::token(&self.0, SyntaxKind::STRING_SUFFIX)
    }

    /// The interpolations embedded in the command, in source order.
    pub fn interpolations(&self) -> AstChildren<Interpolation> {
        support::children(&self.0)
    }
}

impl Interpolation {
    /// The bare interpolated identifier token for `$ident` (absent for `$(expr)`).
    pub fn ident(&self) -> Option<Ident> {
        child_token(&self.0)
    }

    /// The interpolated expression for `$(expr)` (absent for `$ident`).
    pub fn expr(&self) -> Option<Expr> {
        support::child(&self.0)
    }
}

impl BinaryExpr {
    /// The left operand.
    pub fn lhs(&self) -> Option<Expr> {
        support::child(&self.0)
    }

    /// The right operand.
    pub fn rhs(&self) -> Option<Expr> {
        support::children(&self.0).nth(1)
    }

    /// The operator token (the first operator between the operands).
    pub fn op(&self) -> Option<Operator> {
        child_token(&self.0)
    }
}

impl AssignmentExpr {
    /// The assignment target (left of the operator).
    pub fn lhs(&self) -> Option<Expr> {
        support::child(&self.0)
    }

    /// The assigned value (right of the operator).
    pub fn rhs(&self) -> Option<Expr> {
        support::children(&self.0).nth(1)
    }

    /// The assignment operator token (`=`, `+=`, `.=`, ...).
    pub fn op(&self) -> Option<Operator> {
        child_token(&self.0)
    }
}

impl ArrowExpr {
    /// The parameter side (left of `->`).
    pub fn lhs(&self) -> Option<Expr> {
        support::child(&self.0)
    }

    /// The body side (right of `->`).
    pub fn rhs(&self) -> Option<Expr> {
        support::children(&self.0).nth(1)
    }
}

impl UnaryExpr {
    /// The operator token.
    pub fn op(&self) -> Option<Operator> {
        child_token(&self.0)
    }

    /// The operand.
    pub fn operand(&self) -> Option<Expr> {
        support::child(&self.0)
    }
}

impl SplatExpr {
    /// The splatted expression (the `x` in `x...`).
    pub fn expr(&self) -> Option<Expr> {
        support::child(&self.0)
    }
}

impl ParenExpr {
    /// The parenthesized inner expression.
    pub fn expr(&self) -> Option<Expr> {
        support::child(&self.0)
    }
}

impl CallExpr {
    /// The callee (the expression being called).
    pub fn callee(&self) -> Option<Expr> {
        support::child(&self.0)
    }

    /// The operator token naming the callee, when the callee is an operator
    /// rather than an ordinary expression: bare (`!=(a, b)`), parenthesized
    /// (`(!=)(a, b)`), or the quoted symbol ending a qualified path
    /// (`Base.:!=(a, b)`, `Base.:(==)(a, b)`). `None` for every other callee
    /// shape.
    pub fn callee_operator(&self) -> Option<Operator> {
        for el in self.0.children_with_tokens() {
            match el {
                rowan::NodeOrToken::Token(token) => {
                    if let Some(op) = Operator::cast(token) {
                        return Some(op);
                    }
                }
                rowan::NodeOrToken::Node(node) => {
                    return match node.kind() {
                        SyntaxKind::PAREN_EXPR => paren_operator(&node),
                        // A qualified path callee (`Base.:!=`): the operator is
                        // the quoted symbol ending the path.
                        SyntaxKind::BINARY_EXPR => node
                            .children()
                            .last()
                            .filter(|last| last.kind() == SyntaxKind::QUOTE_SYM)
                            .and_then(|quote| quote_sym_operator(&quote)),
                        _ => None,
                    };
                }
            }
        }
        None
    }
}

/// The lone operator token directly inside a `PAREN_EXPR` (`(!=)`), if any.
fn paren_operator(paren: &SyntaxNode) -> Option<Operator> {
    paren
        .children_with_tokens()
        .filter_map(|el| el.into_token())
        .find_map(Operator::cast)
}

/// The operator a `QUOTE_SYM` quotes (`:!=`, `:(==)`), skipping the leading
/// quoting `:` (itself an operator kind).
fn quote_sym_operator(quote: &SyntaxNode) -> Option<Operator> {
    let mut seen_quote_colon = false;
    for el in quote.children_with_tokens() {
        match el {
            rowan::NodeOrToken::Token(token) => {
                if !seen_quote_colon && token.kind() == SyntaxKind::COLON {
                    seen_quote_colon = true;
                } else if let Some(op) = Operator::cast(token) {
                    return Some(op);
                }
            }
            rowan::NodeOrToken::Node(node) if node.kind() == SyntaxKind::PAREN_EXPR => {
                return paren_operator(&node);
            }
            _ => {}
        }
    }
    None
}

impl IndexExpr {
    /// The expression being indexed.
    pub fn base(&self) -> Option<Expr> {
        support::child(&self.0)
    }
}

impl DotCallExpr {
    /// The callee of the broadcast call.
    pub fn callee(&self) -> Option<Expr> {
        support::child(&self.0)
    }
}

impl CurlyExpr {
    /// The base expression the type parameters apply to, e.g. `Vector` in
    /// `Vector{T}`.
    pub fn base(&self) -> Option<Expr> {
        support::child(&self.0)
    }
}

impl ArgList {
    /// The positional/keyword argument nodes (`ARG`, `KEYWORD_ARG`), in source
    /// order. Each [`Arg`] wraps the argument expression; keyword arguments are
    /// reached via [`Self::keyword_args`].
    pub fn args(&self) -> AstChildren<Arg> {
        support::children(&self.0)
    }

    /// The keyword arguments (`x = v`), in source order.
    pub fn keyword_args(&self) -> AstChildren<KeywordArg> {
        support::children(&self.0)
    }
}

impl Arg {
    /// The argument's expression.
    pub fn expr(&self) -> Option<Expr> {
        support::child(&self.0)
    }
}

impl KeywordArg {
    /// The keyword name (the left of `=`).
    pub fn name(&self) -> Option<Name> {
        support::child(&self.0)
    }

    /// The keyword value (the right of `=`).
    pub fn value(&self) -> Option<Expr> {
        support::children(&self.0).nth(1)
    }
}

impl MacroCall {
    /// The macro name, e.g. `@m`, `@.`, or `Base.@time`.
    pub fn name(&self) -> Option<MacroName> {
        support::child(&self.0)
    }
}

impl MacroName {
    /// The macro's simple-name token: the final `IDENT` (e.g. `time` in
    /// `Base.@time`), or the `DOT` for the broadcast macro `@.`.
    pub fn macro_token(&self) -> Option<SyntaxToken> {
        self.0
            .children_with_tokens()
            .filter_map(|e| e.into_token())
            .filter(|t| matches!(t.kind(), SyntaxKind::IDENT | SyntaxKind::DOT))
            .last()
    }
}

impl TypeAnnotation {
    /// The `::` operator token.
    pub fn op(&self) -> Option<SyntaxToken> {
        support::token(&self.0, SyntaxKind::COLON_COLON)
    }
}

impl IfExpr {
    /// The `then` branch block. (The condition is [`HasCondition::condition`].)
    pub fn then_body(&self) -> Option<Block> {
        support::child(&self.0)
    }

    /// The `elseif` clauses, in source order.
    pub fn elseif_clauses(&self) -> AstChildren<ElseifClause> {
        support::children(&self.0)
    }

    /// The trailing `else` clause, if any.
    pub fn else_clause(&self) -> Option<ElseClause> {
        support::child(&self.0)
    }
}

impl Condition {
    /// The test expression, unwrapping a single parenthesized layer
    /// (`if (x) ...` yields the `x`). Centralizes the paren-unwrap that
    /// condition consumers would otherwise hand-roll.
    pub fn expr(&self) -> Option<Expr> {
        match support::child::<Expr>(&self.0)? {
            Expr::ParenExpr(paren) => paren.expr(),
            other => Some(other),
        }
    }
}

impl FunctionDef {
    /// The function signature, e.g. `g(x)`.
    pub fn signature(&self) -> Option<Signature> {
        support::child(&self.0)
    }
}

impl Signature {
    /// The signature's core expression (a `CALL_EXPR`, a bare `NAME`, ...).
    pub fn expr(&self) -> Option<Expr> {
        support::child(&self.0)
    }
}

impl ModuleDef {
    /// The module's name, e.g. `M` in `module M ... end`. (The body is
    /// [`HasBody::body`].)
    pub fn name(&self) -> Option<Name> {
        support::child::<Signature>(&self.0).and_then(|sig| support::child(&sig.0))
    }
}

impl ForBinding {
    /// The loop variable/pattern (left of `in`/`=`).
    pub fn pattern(&self) -> Option<Expr> {
        support::child(&self.0)
    }

    /// The iterable expression (right of `in`/`=`).
    pub fn iterable(&self) -> Option<Expr> {
        support::children(&self.0).nth(1)
    }
}

impl CatchClause {
    /// The bound exception variable (`catch e`), if named. (The body is
    /// [`HasBody::body`].)
    pub fn variable(&self) -> Option<Name> {
        support::child(&self.0)
    }
}

impl DoExpr {
    /// The parameters on the `do` line, e.g. `x, y` in `f(a) do x, y`. Absent for
    /// a bare `do`.
    pub fn params(&self) -> Option<DoParams> {
        support::child(&self.0)
    }
}

impl Root {
    /// The top-level items of the file, in source order.
    pub fn items(&self) -> AstChildren<Expr> {
        support::children(&self.0)
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::ast::tokens::AstToken;
    use crate::ast::traits::{HasArgList, HasBody, HasCondition};
    use crate::parser::parse;

    /// The first node in the parse of `src` castable to `T`.
    fn find<T: AstNode<Language = JuliaLanguage>>(src: &str) -> T {
        parse(src)
            .cst
            .descendants()
            .find_map(T::cast)
            .expect("node of the requested kind present")
    }

    fn expr_text(expr: Option<Expr>) -> String {
        expr.expect("expression present")
            .syntax()
            .text()
            .to_string()
    }

    #[test]
    fn binary_expr_operands_and_operator() {
        let bin: BinaryExpr = find("a + b\n");
        assert_eq!(expr_text(bin.lhs()), "a");
        assert_eq!(expr_text(bin.rhs()), "b");
        assert_eq!(bin.op().unwrap().text(), "+");
    }

    #[test]
    fn assignment_operands_and_operator() {
        let assign: AssignmentExpr = find("x = f(1)\n");
        assert_eq!(expr_text(assign.lhs()), "x");
        assert!(matches!(assign.rhs(), Some(Expr::CallExpr(_))));
        assert_eq!(assign.op().unwrap().text(), "=");
    }

    #[test]
    fn call_callee_and_args() {
        let call: CallExpr = find("g(a, b)\n");
        assert_eq!(expr_text(call.callee()), "g");
        let args = call.arg_list().expect("arg list");
        let texts: Vec<String> = args
            .args()
            .map(|a| a.expr().unwrap().syntax().text().to_string())
            .collect();
        assert_eq!(texts, ["a", "b"]);
    }

    #[test]
    fn call_callee_operator_shapes() {
        // Bare, parenthesized, and qualified (`:!=` and `:(==)`) operator
        // callees all surface the operator token.
        let call: CallExpr = find("!=(a, b)\n");
        assert_eq!(call.callee_operator().unwrap().text(), "!=");
        let call: CallExpr = find("(!=)(a, b)\n");
        assert_eq!(call.callee_operator().unwrap().text(), "!=");
        let call: CallExpr = find("Base.:!=(a, b)\n");
        assert_eq!(call.callee_operator().unwrap().text(), "!=");
        let call: CallExpr = find("Base.:(==)(a, b)\n");
        assert_eq!(call.callee_operator().unwrap().text(), "==");
        // Ordinary callees have no operator name.
        let call: CallExpr = find("g(a, b)\n");
        assert!(call.callee_operator().is_none());
        let call: CallExpr = find("Base.g(a, b)\n");
        assert!(call.callee_operator().is_none());
    }

    #[test]
    fn if_condition_body_and_else() {
        let if_expr: IfExpr = find("if x\n    1\nelse\n    2\nend\n");
        let cond = if_expr.condition().expect("condition");
        assert_eq!(expr_text(cond.expr()), "x");
        assert!(if_expr.then_body().is_some());
        assert!(if_expr.else_clause().and_then(|e| e.body()).is_some());
    }

    #[test]
    fn literal_bool_token() {
        assert_eq!(
            find::<Literal>("true\n").bool_token().unwrap().text(),
            "true"
        );
        assert_eq!(
            find::<Literal>("false\n").bool_token().unwrap().text(),
            "false"
        );
        assert!(find::<Literal>("1\n").bool_token().is_none());
    }

    #[test]
    fn condition_unwraps_one_paren_layer() {
        let cond: Condition = find("if (x = 1)\n    1\nend\n");
        // A single paren layer is peeled: the inner assignment surfaces.
        assert!(matches!(cond.expr(), Some(Expr::AssignmentExpr(_))));
    }

    #[test]
    fn function_signature_and_body() {
        let func: FunctionDef = find("function f(x)\n    x\nend\n");
        assert_eq!(expr_text(func.signature().and_then(|s| s.expr())), "f(x)");
        assert!(func.body().is_some());
    }

    #[test]
    fn expr_dispatches_known_kinds() {
        assert!(matches!(
            Expr::cast(find::<CallExpr>("f()\n").syntax().clone()),
            Some(Expr::CallExpr(_))
        ));
        assert!(matches!(
            Expr::cast(find::<Name>("x\n").syntax().clone()),
            Some(Expr::Name(_))
        ));
    }

    #[test]
    fn expr_falls_back_to_other_for_unwrapped_kinds() {
        // `a < b < c` parses to COMPARISON_EXPR, an expression kind with no
        // dedicated wrapper: it must still round-trip through `Expr::Other`,
        // not vanish.
        let cmp = parse("a < b < c\n")
            .cst
            .descendants()
            .find(|n| n.kind() == SyntaxKind::COMPARISON_EXPR)
            .expect("comparison expr");
        assert!(matches!(Expr::cast(cmp), Some(Expr::Other(_))));
    }

    #[test]
    fn non_expression_nodes_do_not_cast_to_expr() {
        let sig = find::<FunctionDef>("function f()\nend\n")
            .signature()
            .unwrap();
        assert!(Expr::cast(sig.syntax().clone()).is_none());
    }

    #[test]
    fn module_def_name_and_body() {
        let module: ModuleDef = find("module M\nx = 1\nend\n");
        assert_eq!(module.name().unwrap().syntax().text(), "M");
        assert!(module.body().is_some());
        let bare: ModuleDef = find("baremodule B\nend\n");
        assert_eq!(bare.name().unwrap().syntax().text(), "B");
    }

    #[test]
    fn missing_children_yield_none() {
        // A bare `do` block has no `DO_PARAMS`.
        let do_expr: DoExpr = find("f() do\n    1\nend\n");
        assert!(do_expr.params().is_none());
    }
}
